/* MCQ bank. Options carry NO letter prefixes; the UI renders A./B./C./D. answer = 0-based index of correct option. */
window.QUESTIONS = { ch1: [], ch2: [], ch3: [], ch4: [], final: [] };
window.QUESTIONS.ch1 = [
{q:"Which set of three properties forms the core foundation of information security?",options:["Confidentiality, Integrity, Availability","Authentication, Auditing, Access","Prevention, Detection, Correction","Encryption, Hashing, Signing"],answer:0,explanation:"The CIA triad \u2014 Confidentiality, Integrity, and Availability \u2014 is the cornerstone every security control ultimately supports."},
{q:"A company discovers that customer records were viewed by an unauthorized outsider. Which property was primarily violated?",options:["Availability of the data","Confidentiality of the data","Integrity of the data","Redundancy of the data"],answer:1,explanation:"Unauthorized viewing is a disclosure problem, which is exactly what confidentiality protects against."},
{q:"What does integrity, as a security property, mainly guarantee about data?",options:["It remains hidden from outsiders","It stays accurate and unaltered","It is always quickly reachable","It is stored in many copies"],answer:1,explanation:"Integrity ensures information is accurate, consistent, and has not been changed by anyone unauthorized."},
{q:"A denial-of-service attack floods a server so users cannot reach it. Which property is targeted?",options:["Confidentiality of records","Integrity of records","Availability of service","Authenticity of users"],answer:2,explanation:"Denial-of-service overwhelms a system so legitimate users lose access, directly attacking availability."},
{q:"Which statement best captures why security is described as holistic?",options:["It depends only on strong encryption tools","It combines technology, policy, and people","It relies solely on firewall hardware","It is achieved by one trusted product"],answer:1,explanation:"Security blends technical safeguards, organizational policy, and human awareness; the weakest of these limits overall strength."},
{q:"In security terms, what is an asset?",options:["A flaw waiting to be exploited","Anything of value worth protecting","A person who attacks a system","A control that blocks intruders"],answer:1,explanation:"An asset is anything valuable to an organization \u2014 data, software, hardware, networks, or reputation \u2014 that needs protection."},
{q:"What is the correct definition of a threat?",options:["A weakness in a configured system","A potential cause of harm to assets","The measured chance of any loss","A recovery step taken after damage"],answer:1,explanation:"A threat is a potential event or actor capable of causing harm \u2014 the 'what could go wrong'."},
{q:"How is a vulnerability best described?",options:["An attacker seeking financial gain","A weakness a threat can exploit","The product of likelihood and impact","A policy that limits user actions"],answer:1,explanation:"A vulnerability is a weakness \u2014 like outdated software or a weak password \u2014 that a threat can take advantage of."},
{q:"Risk in information security is most accurately understood as which combination?",options:["Threat added to a single asset","Likelihood combined with impact","Vulnerability minus any controls","Cost divided by total assets"],answer:1,explanation:"Risk arises when a threat exploits a vulnerability and is measured by how likely it is and how damaging it would be."},
{q:"An organization patches outdated software across its network. Which part of the risk equation does this most directly reduce?",options:["The number of active threats","The exposure from vulnerabilities","The value of its core assets","The impact of every breach"],answer:1,explanation:"You usually cannot remove threats, but patching closes vulnerabilities, which lowers overall risk."},
{q:"Which sequence correctly orders the risk-management process?",options:["Mitigate, monitor, identify, assess","Identify, assess, mitigate, monitor","Assess, identify, monitor, mitigate","Monitor, mitigate, assess, identify"],answer:1,explanation:"The cycle runs Identify \u2192 Assess \u2192 Mitigate \u2192 Monitor, then repeats continuously."},
{q:"Why is risk management described as a continuous loop rather than a one-time task?",options:["Budgets are renewed every fiscal year","New threats and changes keep emerging","Employees rotate through departments","Hardware is replaced on a schedule"],answer:1,explanation:"Because the threat landscape constantly shifts, organizations must keep monitoring and reassessing to stay protected."},
{q:"Which attacker type is primarily motivated by ideology or a political cause?",options:["Cybercriminals chasing profit","Hacktivists pursuing a cause","State actors seeking espionage","Insiders misusing their access"],answer:1,explanation:"Hacktivists are driven by ideology or political goals rather than money or state interests."},
{q:"An employee accidentally emails a confidential file to the wrong recipient. This is an example of which threat category?",options:["A state-sponsored operation","An unintentional insider threat","An external hacktivist attack","A distributed denial of service"],answer:1,explanation:"Insider threats include accidental misuse of legitimate access, not only deliberate sabotage."},
{q:"Which description best fits malware?",options:["Software designed to cause harm","A weakness in network design","A policy enforcing least privilege","A method of verifying identity"],answer:0,explanation:"Malware is malicious software \u2014 viruses, worms, trojans, spyware, ransomware \u2014 created to damage or exploit systems."},
{q:"Phishing attacks succeed mainly by exploiting which weakness?",options:["Flaws in encryption algorithms","Human trust and behavior","Gaps in physical door locks","Errors in database indexing"],answer:1,explanation:"Phishing is social engineering: it manipulates human psychology rather than breaking technical defenses."},
{q:"Which defense is generally the strongest countermeasure against phishing?",options:["Installing more server memory","Ongoing user awareness training","Increasing network bandwidth","Adding additional disk backups"],answer:1,explanation:"Since phishing targets people, educating and training users is the most effective defense."},
{q:"A firewall that blocks malicious traffic before it enters is which kind of control?",options:["A corrective control","A preventive control","A detective control","A recovery control"],answer:1,explanation:"Preventive controls stop incidents before they happen; a firewall blocking traffic is a classic example."},
{q:"An intrusion-detection system that alerts staff to an ongoing attack is best classified as which control?",options:["A preventive control","A detective control","A corrective control","A physical control"],answer:1,explanation:"Detective controls identify incidents as they occur or after the fact; IDS alerting is detective."},
{q:"Restoring systems from backups after an incident is an example of which control function?",options:["Preventive function","Corrective function","Detective function","Deterrent function"],answer:1,explanation:"Corrective controls help recover and restore normal operation after an incident, such as restoring from backup."},
{q:"Security awareness training for staff falls under which category of control?",options:["Technical control","Administrative control","Physical control","Cryptographic control"],answer:1,explanation:"Administrative controls are policies, procedures, and training that guide how people behave."},
{q:"Door locks and security guards protecting a server room are which type of control?",options:["Technical controls","Physical controls","Administrative controls","Logical controls"],answer:1,explanation:"Physical controls protect facilities and hardware using tangible barriers like locks and guards."},
{q:"What is the central idea behind defense in depth?",options:["Rely on one very strong barrier","Layer multiple overlapping controls","Encrypt only the most vital files","Trust users inside the network"],answer:1,explanation:"Defense in depth uses several layered controls so that if one fails, others still protect the system."},
{q:"Which statement about the human factor in security is most accurate?",options:["Technology alone removes human risk","Most breaches involve human error","Training has no measurable effect","Insiders are never a real concern"],answer:1,explanation:"A large share of breaches trace back to human mistakes, so culture and training are essential."},
{q:"What does authentication establish?",options:["What actions a user may perform","Who a user actually is","Which files were recently changed","How long a session may last"],answer:1,explanation:"Authentication verifies identity \u2014 proving who you are \u2014 before any access is granted."},
{q:"What does authorization determine after a user is authenticated?",options:["Whether their identity is genuine","What they are permitted to do","How their password was stored","When their account was created"],answer:1,explanation:"Authorization decides what an already-authenticated user is allowed to access or perform."},
{q:"Which scenario best illustrates the difference between authentication and authorization?",options:["Encrypting a file then deleting it","Logging in, then seeing only your account","Backing up data then restoring it","Scanning a network then patching it"],answer:1,explanation:"Logging in proves identity (authentication); being limited to your own account is authorization."},
{q:"Multi-factor authentication improves security mainly by doing what?",options:["Requiring several proofs of identity","Encrypting all stored passwords","Replacing the need for any policy","Granting broad access to everyone"],answer:0,explanation:"MFA combines multiple independent factors, making unauthorized access far harder even if one factor leaks."},
{q:"The principle of least privilege recommends that users receive what level of access?",options:["The maximum access available","Only the access they truly need","Access equal to their manager","Temporary access to everything"],answer:1,explanation:"Least privilege grants the minimum permissions necessary, limiting potential damage from misuse or compromise."},
{q:"What does encryption fundamentally do to information?",options:["Removes it from storage entirely","Converts readable data to unreadable form","Copies it to multiple locations","Verifies who created the data"],answer:1,explanation:"Encryption transforms readable plaintext into unreadable ciphertext that requires a key to recover."},
{q:"A zero-day exploit is dangerous specifically because it targets a flaw that has what status?",options:["A widely deployed patch","No available fix yet","A known, monitored signature","A low likelihood of use"],answer:1,explanation:"A zero-day attacks a vulnerability before any patch exists, leaving defenders with no ready fix."},
{q:"In a man-in-the-middle attack, what does the attacker primarily do?",options:["Floods a server with requests","Intercepts communication between parties","Encrypts the victim's files for ransom","Guesses passwords through brute force"],answer:1,explanation:"A man-in-the-middle secretly intercepts (and may alter) communication flowing between two parties."},
{q:"SQL injection is an attack that works by doing what?",options:["Overloading the network bandwidth","Inserting malicious database commands","Cracking encrypted password files","Impersonating a trusted website"],answer:1,explanation:"SQL injection inserts malicious commands into queries to manipulate or expose a database."},
{q:"Why is classifying assets by sensitivity an important early step?",options:["It removes all system threats","It focuses protection where it matters","It eliminates the need for backups","It guarantees full availability"],answer:1,explanation:"Classification lets an organization prioritize spending on its most valuable and sensitive assets."},
{q:"Which best describes ransomware?",options:["Software that quietly logs keystrokes","Malware that locks data for payment","A tool that verifies file integrity","A protocol for secure messaging"],answer:1,explanation:"Ransomware encrypts or locks a victim's data and demands payment to restore access."},
{q:"What is the main goal of network segmentation?",options:["To speed up all data transfers","To limit how far an attacker can move","To remove the need for firewalls","To store data in fewer places"],answer:1,explanation:"Segmentation divides a network so a breach in one segment cannot easily spread across the whole environment."},
{q:"A zero-trust architecture is built on which core assumption?",options:["Internal users are always safe","No user or device is trusted by default","Perimeter firewalls are sufficient","Encryption replaces all access checks"],answer:1,explanation:"Zero trust never assumes trust based on location; every request is verified regardless of origin."},
{q:"Why must security work comply with data-protection laws and ethics?",options:["It speeds up network performance","It reduces legal liability and protects reputation","It removes the need for encryption","It guarantees zero future attacks"],answer:1,explanation:"Compliance with legal and ethical standards limits liability and safeguards an organization's reputation."},
{q:"Which pairing of attacker and motivation is correct?",options:["Cybercriminal motivated by ideology","State actor motivated by espionage","Hacktivist motivated by pure profit","Insider motivated by national defense"],answer:1,explanation:"State-sponsored actors typically pursue espionage and strategic advantage on behalf of a nation."},
{q:"Separation of duties helps reduce insider threats by doing what?",options:["Giving one person full control","Splitting critical tasks among people","Removing the need for logging","Allowing shared single accounts"],answer:1,explanation:"Separation of duties divides sensitive tasks so no single individual can abuse a process alone."},
{q:"Behavior-based monitoring is increasingly used because advanced malware can do what?",options:["Run only on outdated hardware","Evade signature-based detection","Spread only through physical media","Encrypt nothing on the disk"],answer:1,explanation:"Sophisticated malware can dodge signature tools, so defenders watch for abnormal behavior instead."},
{q:"Which example best represents a corrective control working with a detective control?",options:["A lock paired with a policy","An alarm detecting fire, then sprinklers acting","A password paired with encryption","A guard paired with a fence"],answer:1,explanation:"Detection (alarm) identifies the incident and the corrective measure (sprinklers) responds to limit damage."},
{q:"Why can strengthening one part of the CIA triad sometimes weaken another?",options:["The properties are unrelated entirely","Trade-offs exist between the goals","Only confidentiality ever matters","Availability is never affected"],answer:1,explanation:"For example, heavy encryption can slow retrieval, trading some availability for confidentiality; balance is required."},
{q:"What is the primary purpose of an incident-response plan?",options:["To prevent every possible attack","To guide reaction and recovery after incidents","To replace all technical controls","To classify assets by value"],answer:1,explanation:"Incident response defines how an organization detects, contains, and recovers from security incidents."},
{q:"Which of the following is the best example of an availability-focused safeguard?",options:["Encrypting data at rest","Maintaining redundant backups and failover","Hashing stored passwords","Signing software releases"],answer:1,explanation:"Redundancy, backups, and failover keep systems usable, which directly supports availability."},
{q:"A trojan is best described as malware that does what?",options:["Spreads by copying itself automatically","Disguises itself as legitimate software","Encrypts files for a ransom payment","Floods a target with network traffic"],answer:1,explanation:"A trojan masquerades as harmless or useful software to trick users into running it."},
{q:"Why is identifying assets considered the first step in security planning?",options:["Threats disappear once listed","You cannot protect what you have not identified","It removes all system vulnerabilities","It makes encryption unnecessary"],answer:1,explanation:"Without knowing what assets exist, an organization cannot decide what to protect or how."},
{q:"Which combination correctly reflects the relationship among the three core terms?",options:["Threat exploits vulnerability, creating risk","Risk exploits threat, creating vulnerability","Vulnerability exploits risk, creating threat","Threat removes vulnerability, ending risk"],answer:0,explanation:"A threat exploiting a vulnerability is precisely what produces risk."},
{q:"Role-based access control supports security mainly by doing what?",options:["Giving permissions based on job roles","Removing the need to authenticate","Encrypting every stored password","Granting all users equal access"],answer:0,explanation:"RBAC assigns permissions according to a user's role, keeping access aligned with job needs."},
{q:"Which statement about future security trends is most accurate?",options:["AI-driven detection and automation are growing","Human training is becoming irrelevant","Perimeter-only defense is the future standard","Encryption is being phased out entirely"],answer:0,explanation:"Defenses increasingly rely on automation, AI-driven detection, and zero-trust models to keep pace with threats."}
];

window.QUESTIONS.ch2 = [
{q:"In access-control terms, what is a subject?",options:["A passive resource being protected","An active entity that performs operations","A permission attached to a file","A rule limiting state transitions"],answer:1,explanation:"A subject is an active entity \u2014 a user, process, or service \u2014 that initiates operations in the system."},
{q:"Which of the following is the best example of an object?",options:["A user running a program","A background system service","A stored database file","A process requesting access"],answer:2,explanation:"Objects are passive resources that are acted upon, such as files, memory, or printers."},
{q:"What fundamentally distinguishes a subject from an object?",options:["Subjects are larger than objects","Subjects act while objects are acted upon","Objects always belong to subjects","Objects can never be deleted"],answer:1,explanation:"Subjects are active initiators of operations; objects are passive targets that only respond."},
{q:"In the access-control model, what does a right represent?",options:["A specific operation a subject may perform","A weakness that can be exploited","A user's physical office location","The size of a stored file"],answer:0,explanation:"A right (access right) defines a specific permitted operation a subject may perform on an object."},
{q:"Which classic right allows viewing content without changing it?",options:["Write access","Read access","Execute access","Control access"],answer:1,explanation:"Read lets a subject view an object's content; data is retrieved but not modified."},
{q:"Improper granting of which right poses the most direct threat to integrity?",options:["Read access","Write access","Execute access","Browse access"],answer:1,explanation:"Write access allows modification, so granting it improperly threatens the integrity of data."},
{q:"The control (own) right is especially sensitive because it allows a subject to do what?",options:["Run any installed program","Grant or revoke others' rights","View hidden system files","Increase available storage"],answer:1,explanation:"The control right lets a subject manage permissions \u2014 granting or revoking rights \u2014 which can lead to privilege escalation."},
{q:"What does an access-control matrix represent?",options:["Network traffic between hosts","All subject-object permissions in a table","The encryption keys in a system","A list of detected vulnerabilities"],answer:1,explanation:"The matrix tabulates all permissions, with subjects as rows, objects as columns, and rights in the cells."},
{q:"In an access-control matrix, what do the rows and columns represent respectively?",options:["Objects and subjects","Subjects and objects","Rights and conditions","Files and folders"],answer:1,explanation:"By convention, rows represent subjects and columns represent objects in the access-control matrix."},
{q:"A single cell of the access-control matrix contains what information?",options:["The rights a subject holds over an object","The total number of system users","The encryption strength of a file","The history of all logins"],answer:0,explanation:"Each cell lists the set of rights that the row's subject has over the column's object."},
{q:"Why is the access-control matrix described as sparse in real systems?",options:["It stores duplicate permissions everywhere","Most cells are empty of any rights","It contains only encrypted entries","It changes its size every second"],answer:1,explanation:"Most subjects have no rights to most objects, so the vast majority of cells are empty."},
{q:"What practical problem arises from storing the full access-control matrix directly?",options:["It is too small to be useful","It wastes enormous storage on empty cells","It cannot represent any rights","It encrypts data automatically"],answer:1,explanation:"Because the matrix is mostly empty, storing it in full wastes huge amounts of space, so optimized structures are used."},
{q:"An access control list (ACL) organizes permissions from whose perspective?",options:["The subject's perspective","The object's perspective","The administrator's perspective","The network's perspective"],answer:1,explanation:"An ACL is stored per object, listing which subjects may access it \u2014 it corresponds to a column of the matrix."},
{q:"An ACL corresponds to which part of the access-control matrix?",options:["A single row","A single column","A diagonal entry","The entire matrix"],answer:1,explanation:"Because an ACL is organized per object, it represents one column of the access-control matrix."},
{q:"A capability list organizes permissions from whose perspective?",options:["The object's perspective","The subject's perspective","The auditor's perspective","The vendor's perspective"],answer:1,explanation:"A capability list is stored per subject, describing which objects that subject may access \u2014 it is a row of the matrix."},
{q:"A capability list corresponds to which part of the access-control matrix?",options:["A single column","A single row","A merged cell","The matrix header"],answer:1,explanation:"Because a capability list is organized per subject, it represents one row of the matrix."},
{q:"Which question is easiest to answer using an ACL?",options:["What can this user access overall?","Who can access this particular object?","How many rights exist in total?","When was a right last revoked?"],answer:1,explanation:"Since an ACL lists subjects per object, it readily answers 'who can access this object?'"},
{q:"Which question is easiest to answer using a capability list?",options:["Who can access this single file?","What objects can this subject access?","How large is the object?","Which cells are empty?"],answer:1,explanation:"A capability list groups by subject, so it readily answers 'what can this subject access?'"},
{q:"Revoking access to one specific object for everyone is generally easier with which structure?",options:["Capability lists","Access control lists","A sparse diagonal","A random matrix"],answer:1,explanation:"Because an ACL gathers all subjects for one object in one place, removing access there is straightforward."},
{q:"A capability is best described as which of the following?",options:["An entry in an object's permission list","An unforgeable token granting authority","A weakness that an attacker exploits","A log of recent access attempts"],answer:1,explanation:"A capability is an unforgeable token held by a subject that proves its authority to access an object."},
{q:"Why must a capability token be unforgeable?",options:["To make it easier to copy","To prevent subjects from faking authority","To reduce its storage size","To allow public sharing"],answer:1,explanation:"If tokens could be forged, any subject could fabricate authority it was never granted, breaking access control."},
{q:"What is a system state in the access-control model?",options:["The speed of the network","The full configuration of subjects, objects, and rights","The number of failed logins","The encryption algorithm in use"],answer:1,explanation:"A system state captures the complete arrangement of subjects, objects, and the rights connecting them at one moment."},
{q:"What is a state transition?",options:["An operation that changes the configuration","A permanently fixed configuration","A type of encryption key","A backup of stored files"],answer:0,explanation:"A state transition is an operation \u2014 like granting or revoking a right \u2014 that moves the system to a new state."},
{q:"Which set of operations are the primitive commands that change protection state?",options:["Encrypt, decrypt, sign, verify","Grant, revoke, create, delete","Read, hash, store, send","Login, logout, pause, resume"],answer:1,explanation:"The primitive commands grant a right, revoke a right, create an entity, or delete an entity, transforming the matrix."},
{q:"What does the 'grant' command do to the access-control matrix?",options:["Removes a right from a cell","Adds a right to a cell","Deletes a whole column","Encrypts a row"],answer:1,explanation:"Granting adds a right to the appropriate matrix cell, expanding a subject's permissions."},
{q:"What does the 'create' command introduce into the system?",options:["A new right within a cell","A new subject or object","A new encryption key","A new network link"],answer:1,explanation:"The create command introduces a new subject or object, adding a row or column to the matrix."},
{q:"What is delegation in access control?",options:["Encrypting a file before sharing","A subject granting a held right to another subject","Deleting a user from the system","Auditing the access logs"],answer:1,explanation:"Delegation occurs when one subject passes a permission it holds to another, adding a new matrix entry."},
{q:"A key rule of delegation is that a subject can only delegate what?",options:["Any right it wishes to invent","A right it actually possesses","Rights belonging to other users","Rights that no one holds"],answer:1,explanation:"You cannot give away a permission you do not have; delegation is limited to rights the delegator already holds."},
{q:"Why is uncontrolled delegation a security concern?",options:["It slows down the network","It lets rights propagate widely","It deletes important objects","It encrypts files permanently"],answer:1,explanation:"Delegation lets authority spread from subject to subject; if uncontrolled, permissions propagate and security drifts."},
{q:"What does the safety problem ask about a system?",options:["Whether the network is fast enough","Whether a right can ever leak to a subject","Whether backups are recent","Whether passwords are strong"],answer:1,explanation:"The safety problem asks whether, starting from a configuration, a particular right could ever reach a subject that should not have it."},
{q:"In the safety problem, what is an 'unsafe' state?",options:["A state with no active users","A configuration that violates the policy","A state with full backups","A state with maximum encryption"],answer:1,explanation:"An unsafe state is one in which a right has leaked \u2014 i.e., the configuration violates the intended policy."},
{q:"What did the HRU result establish about the general safety problem?",options:["It is always easy to solve","It is undecidable in general","It requires no assumptions","It depends only on encryption"],answer:1,explanation:"Harrison-Ruzzo-Ullman showed that, for general systems, there is no algorithm that can always decide safety."},
{q:"Because general safety is undecidable, system designers commonly do what?",options:["Ignore safety entirely","Restrict systems to analyzable models","Remove all access controls","Encrypt the access matrix"],answer:1,explanation:"Designers deliberately limit expressiveness so the resulting, simpler models can be analyzed for safety."},
{q:"A conditional command is one that executes only when what is true?",options:["The network is idle","Certain preconditions hold","All users are logged out","The disk is full"],answer:1,explanation:"A conditional command runs only if its preconditions are met, such as 'A may grant read only if A owns the file'."},
{q:"Conditional commands enforce policy but have what drawback?",options:["They make analysis harder","They delete user accounts","They disable encryption","They remove all rights"],answer:0,explanation:"While conditions help enforce policy, they add complexity that makes formal safety analysis more difficult."},
{q:"Which property makes a process able to be both a subject and an object?",options:["Its file size","Whether it initiates or receives an operation","Its encryption level","Its creation date"],answer:1,explanation:"A process acts as a subject when it initiates an operation and as an object when an operation is performed on it."},
{q:"Why is accountability tied to the concept of subjects?",options:["Subjects store all the data","Actions are traced back to responsible subjects","Subjects cannot be logged","Subjects never change state"],answer:1,explanation:"Because subjects initiate operations, logging their actions allows the system to attribute and audit behavior."},
{q:"Which is the most accurate description of how ACLs are used in real operating systems?",options:["They are purely theoretical only","UNIX and NTFS permissions implement them","They store encryption keys","They replace all authentication"],answer:1,explanation:"Real systems like UNIX file permissions and Windows NTFS implement the ACL concept directly."},
{q:"What is the relationship between the access-control matrix and ACLs or capability lists?",options:["They store unrelated data","ACLs and capabilities are efficient slices of the matrix","The matrix replaces both of them","They encrypt the matrix"],answer:1,explanation:"ACLs (columns) and capability lists (rows) are space-efficient ways to store the same information the matrix represents."},
{q:"If a row 'Bob' and column 'File1' in the matrix is empty, what does it mean?",options:["Bob owns File1 completely","Bob has no rights over File1","File1 is encrypted for Bob","Bob can delete File1"],answer:1,explanation:"An empty cell means the subject holds no rights at all over that object."},
{q:"Which statement about evaluating a system at one instant is correct?",options:["It examines a single system snapshot","It predicts all future attacks","It encrypts the configuration","It deletes unused rights"],answer:0,explanation:"A security evaluation inspects the configuration (snapshot) at one specific moment in time."},
{q:"Why is reasoning about future states important even if the current state is secure?",options:["The current state never matters","A safe state today may become unsafe later","Future states are always identical","Encryption removes the need"],answer:1,explanation:"As rights change through transitions, a currently secure system could later reach an unsafe state, so future states matter."},
{q:"Which of the following is a passive entity in the access-control model?",options:["A user typing commands","A printer receiving a job","A process requesting a file","A service initiating a transfer"],answer:1,explanation:"A printer is acted upon (it receives jobs), making it a passive object rather than an active subject."},
{q:"What is the main advantage of slicing the matrix into ACLs or capability lists?",options:["It increases empty-cell storage","It stores the same information far more compactly","It removes the need for rights","It hides the subjects entirely"],answer:1,explanation:"Slicing avoids storing empty cells, keeping the same permission information while using far less space."},
{q:"In a dynamic system, why does the protection state change frequently?",options:["Users, objects, and rights are constantly added or removed","The encryption key rotates each second","The matrix is read-only","Subjects never perform operations"],answer:0,explanation:"Real systems continually create users, add resources, and grant or revoke rights, producing frequent state changes."},
{q:"Which best illustrates a state transition?",options:["Reading the current permission list","Granting Bob write access to a file","Counting the number of objects","Measuring network latency"],answer:1,explanation:"Granting a right changes the configuration, moving the system from one protection state to another."},
{q:"A subject is sometimes called an 'access initiator' because it does what?",options:["Stores the requested data","Begins every access request","Encrypts the object","Logs other subjects' actions"],answer:1,explanation:"Every operation starts with a subject requesting access, so subjects are the initiators of access."},
{q:"Which scenario shows privilege escalation through the control right?",options:["A user reads a public document","A user with control grants itself admin rights","A user logs out of the system","A user encrypts a personal file"],answer:1,explanation:"If a subject holding the control right grants itself broader rights, it escalates its privileges \u2014 a key risk."},
{q:"Why are objects required to appear explicitly in the access-control model?",options:["Unmodeled objects cannot be protected","Objects must encrypt themselves","Objects initiate their own access","Objects replace subjects"],answer:0,explanation:"If a resource is not represented in the model, no rights govern it, so it cannot be protected."},
{q:"Which pair correctly matches a structure to its matrix orientation?",options:["ACL = row, capability = column","ACL = column, capability = row","Both are full diagonals","Both are single cells"],answer:1,explanation:"An ACL is a column (per object) and a capability list is a row (per subject) of the access-control matrix."}
];

window.QUESTIONS.ch3 = [
{q:"What does a security policy fundamentally do to the states of a system?",options:["Encrypts every possible state","Partitions them into authorized and unauthorized","Counts the total number of states","Deletes all unused states"],answer:1,explanation:"A security policy divides system states into authorized (secure) and unauthorized (non-secure) sets."},
{q:"According to its formal definition, a secure system is one that does what?",options:["Starts authorized and never enters an unauthorized state","Uses the strongest possible encryption","Has no users at all","Stores many backup copies"],answer:0,explanation:"A secure system begins in an authorized state and can never transition into an unauthorized one."},
{q:"A breach of security is best defined as which event?",options:["A scheduled system backup","A system entering an unauthorized state","A user changing their password","A routine software update"],answer:1,explanation:"A breach is precisely the event of the system entering an unauthorized (non-secure) state."},
{q:"Which statement correctly distinguishes policy from mechanism?",options:["Policy is the tool; mechanism is the goal","Policy is what is allowed; mechanism is how it is enforced","They are identical concepts","Mechanism defines authorized states"],answer:1,explanation:"Policy states WHAT is allowed; mechanism is the technique that enforces it (the HOW)."},
{q:"A password check used to enforce a login rule is an example of which concept?",options:["A policy","A mechanism","A breach","A vulnerability"],answer:1,explanation:"The password check is a mechanism \u2014 the tool that enforces the policy about who may log in."},
{q:"The rule 'only managers may approve payments' is best classified as which?",options:["A mechanism","A policy","A cryptosystem","An access token"],answer:1,explanation:"This statement defines what is allowed, making it a policy rather than an enforcement mechanism."},
{q:"Why can a single policy be enforced by many different mechanisms?",options:["Policies and mechanisms are the same","The goal is independent of the specific tool used","Mechanisms cannot enforce policies","Each policy needs exactly one tool"],answer:1,explanation:"Because policy describes the goal, any mechanism capable of achieving that goal can enforce it."},
{q:"In policy terms, confidentiality refers to which property?",options:["Keeping resources usable","Concealing information from unauthorized parties","Preventing unauthorized modification","Logging all user actions"],answer:1,explanation:"Confidentiality is the concealment of information or resources from those not authorized to see them."},
{q:"In policy terms, integrity refers primarily to which property?",options:["The trustworthiness and correctness of data","The concealment of data","The speed of data access","The number of data copies"],answer:0,explanation:"Integrity is the trustworthiness of data \u2014 preventing improper or unauthorized modification."},
{q:"A military (governmental) security policy is developed primarily to provide what?",options:["Integrity","Confidentiality","Availability","Redundancy"],answer:1,explanation:"Military policies focus mainly on confidentiality \u2014 preventing unauthorized disclosure of classified information."},
{q:"A commercial security policy is developed primarily to provide what?",options:["Confidentiality","Integrity","Anonymity","Availability"],answer:1,explanation:"Commercial policies focus mainly on integrity \u2014 preventing unauthorized modification of information."},
{q:"Which concern best characterizes a confidentiality-focused policy?",options:["Preventing unauthorized disclosure","Preventing unauthorized modification","Maximizing system uptime","Reducing storage costs"],answer:0,explanation:"A confidentiality policy is centrally concerned with stopping the disclosure of information."},
{q:"Which concern best characterizes an integrity-focused policy?",options:["Preventing unauthorized disclosure","Preventing unauthorized modification","Improving network speed","Hiding all metadata"],answer:1,explanation:"An integrity policy is centrally concerned with preventing unauthorized changes to information."},
{q:"A bank's main worry that account balances must never be improperly altered reflects which policy emphasis?",options:["Confidentiality","Integrity","Availability","Anonymity"],answer:1,explanation:"Keeping records accurate and unaltered is an integrity concern, typical of commercial policy."},
{q:"A government's main worry that classified files must not be disclosed reflects which policy emphasis?",options:["Integrity","Confidentiality","Availability","Redundancy"],answer:1,explanation:"Preventing disclosure of secrets is a confidentiality concern, typical of military policy."},
{q:"What is the role of a security model?",options:["To replace all mechanisms","To represent a policy abstractly for analysis","To encrypt the policy text","To delete unauthorized states"],answer:1,explanation:"A security model abstractly represents a policy so it can be reasoned about and verified."},
{q:"The HRU result is relevant to security policy because it shows what?",options:["All policies are easy to verify","Determining whether a right can leak is undecidable in general","Encryption is always unbreakable","Policies never need mechanisms"],answer:1,explanation:"HRU showed the general safety question (can a right leak?) is undecidable, limiting what models can guarantee."},
{q:"Why is trust considered an unavoidable foundation of security?",options:["Everything can be verified from scratch","At some point we must rely on unverified assumptions","Trust eliminates all vulnerabilities","Trust replaces the need for policy"],answer:1,explanation:"You cannot verify every component independently, so security ultimately rests on some trusted assumptions."},
{q:"When an administrator installs a vendor's security patch, which is a trust assumption being made?",options:["The patch correctly fixes the flaw","The network is offline forever","The users will never log in","The disk is fully encrypted"],answer:0,explanation:"Installing a patch assumes the vendor wrote it correctly and that it actually fixes the flaw without adding new ones."},
{q:"What is the recommended way to handle trust assumptions in good security design?",options:["Hide them from everyone","Make them explicit and review them","Assume they never fail","Eliminate them completely"],answer:1,explanation:"Good design makes trust assumptions explicit so they can be examined, rather than leaving them hidden."},
{q:"In discretionary access control (DAC), who decides access to a resource?",options:["The system administrator only","The owner of the resource","The originator of the data","A central labeling authority"],answer:1,explanation:"Under DAC, the resource owner decides who may access it, at their discretion."},
{q:"DAC is also referred to by which alternative name?",options:["Mandatory access control","Identity-based access control","Originator-controlled access","Role-based access control"],answer:1,explanation:"DAC is identity-based (IBAC) because access decisions are based on the identity of subjects."},
{q:"In mandatory access control (MAC), who enforces access decisions?",options:["The individual resource owner","The system or organization through rules","The data's originator","Each end user freely"],answer:1,explanation:"Under MAC, the system enforces access using organization-defined rules; individual owners cannot override them."},
{q:"A key feature of MAC compared to DAC is that under MAC a user cannot do what?",options:["Authenticate to the system","Override the system's access rules","Read any authorized file","Log out normally"],answer:1,explanation:"In MAC, even owners cannot grant access the system's mandatory rules forbid, unlike DAC."},
{q:"In originator-controlled access control (ORCON), who controls how information may be redistributed?",options:["The current holder of the data","The originator who created it","The system administrator","Any authorized reader"],answer:1,explanation:"Under ORCON, the originator (creator) dictates redistribution, even after the data has been shared."},
{q:"Which scenario best illustrates ORCON?",options:["A file owner freely sharing as they wish","A recipient unable to forward a document without the creator's permission","The system labeling files by clearance","A user choosing their own password"],answer:1,explanation:"ORCON keeps control with the originator, so even a legitimate recipient cannot redistribute without permission."},
{q:"Which access-control type is most associated with military classification levels?",options:["DAC","MAC","ORCON","IBAC"],answer:1,explanation:"MAC uses system-enforced labels/clearances, making it characteristic of military classification environments."},
{q:"Which access-control type is typical of ordinary file systems where owners set permissions?",options:["MAC","DAC","ORCON","Label-based control"],answer:1,explanation:"Ordinary file systems are discretionary: the file owner sets the permissions, which is DAC."},
{q:"Why is policy ambiguity considered dangerous?",options:["It speeds up enforcement","It lets people interpret rules differently, creating gaps","It removes the need for mechanisms","It guarantees full security"],answer:1,explanation:"Ambiguous policies invite differing interpretations, leaving gaps that attackers can exploit."},
{q:"The phrase 'reasonable personal use' in an email policy is an example of what problem?",options:["Strong encryption","Policy ambiguity","Perfect availability","Mandatory control"],answer:1,explanation:"Such vague wording is ambiguous, making the policy hard to interpret and enforce consistently."},
{q:"Which is a good first step when building a workable security policy?",options:["Pick mechanisms before any goals","State the goals and which CIA properties matter","Encrypt the whole network first","Delete all existing accounts"],answer:1,explanation:"Effective policy starts by stating goals \u2014 deciding which of confidentiality, integrity, and availability matter for which assets."},
{q:"How do availability concerns enter a security policy?",options:["By ensuring authorized access is not blocked","By hiding all information","By preventing every modification","By removing all user rights"],answer:0,explanation:"Availability ensures authorized users can access resources when needed, including resistance to denial-of-service."},
{q:"Which statement about real-world organizational policies is most accurate?",options:["They use only confidentiality, never integrity","They usually combine confidentiality and integrity","They never need availability","They avoid all trust assumptions"],answer:1,explanation:"Although pure definitions separate them, real organizations typically blend confidentiality and integrity goals."},
{q:"A 'confidentiality policy' in the strict sense deals with which property only?",options:["Integrity only","Confidentiality only","Availability only","All three equally"],answer:1,explanation:"In the strict textbook sense, a confidentiality policy concerns only confidentiality."},
{q:"An 'integrity policy' in the strict sense deals with which property only?",options:["Confidentiality only","Integrity only","Availability only","Anonymity only"],answer:1,explanation:"In the strict sense, an integrity policy concerns only integrity \u2014 preventing unauthorized modification."},
{q:"Why must we reason about state transitions, not just the current state, in policy?",options:["States never change","Transitions can move the system toward unauthorized states","Transitions are always secure","Only the first state matters"],answer:1,explanation:"Because operations change configuration, a secure system must avoid transitions that lead into unauthorized states."},
{q:"Origin integrity, a component of integrity, refers to what?",options:["Hiding the data's content","Authenticating the source of data","Maximizing data availability","Counting data copies"],answer:1,explanation:"Origin integrity concerns the authentication of the data's source, complementing data (content) integrity."},
{q:"Which best explains why mechanisms alone cannot guarantee security?",options:["Mechanisms are always perfect","Without a policy, there is no definition of what 'secure' means","Policies are unnecessary","Mechanisms define authorized states themselves"],answer:1,explanation:"A mechanism enforces something, but only a policy defines what secure means; without policy, enforcement has no goal."},
{q:"A layered university email policy that combines general principles, specific rules, and procedures illustrates what?",options:["That policies are always ambiguous","That real policies are built in structured tiers","That mechanisms replace policies","That confidentiality is irrelevant"],answer:1,explanation:"Real policies (like UC's email policy) are often structured into tiers of principles, rules, and procedures."},
{q:"Which is the correct relationship between authorized states and a secure system?",options:["A secure system stays within authorized states","A secure system must visit unauthorized states","Authorized states are always empty","Authorized states require no policy"],answer:0,explanation:"A secure system remains within the authorized set of states for its entire operation."},
{q:"In the DAC model, a notable risk is that owners can do what?",options:["Be forced by the system to share","Pass rights to others at their discretion, leaking access","Never grant any access","Override mandatory labels"],answer:1,explanation:"Because DAC lets owners grant rights freely, they can inadvertently or deliberately leak access \u2014 a known weakness."},
{q:"Which property of MAC makes it strong against insider leaks?",options:["Owners can override rules","The system enforces rules users cannot bypass","There are no labels","Users set their own clearances"],answer:1,explanation:"Because MAC rules are enforced by the system and cannot be overridden by users, insiders cannot freely leak access."},
{q:"ORCON is considered difficult to enforce technically because it requires what?",options:["No control after sharing","Persistent control over redistribution by the originator","Deleting data immediately","Encrypting only metadata"],answer:1,explanation:"ORCON demands the originator retain control over redistribution even after sharing, which is hard to enforce in practice."},
{q:"Which is the best summary of the policy/mechanism relationship?",options:["One policy maps to exactly one mechanism","Many mechanisms can serve one policy and vice versa","Mechanisms define policies","Policies enforce mechanisms"],answer:1,explanation:"A policy can be enforced by many mechanisms, and a mechanism can support many policies; they are distinct layers."},
{q:"Why is stating authorized vs unauthorized states clearly important when writing policy?",options:["It makes the policy ambiguous","It removes ambiguity and supports enforcement","It eliminates the need for trust","It encrypts the policy"],answer:1,explanation:"Clear definitions of allowed and forbidden states reduce ambiguity and make the policy enforceable."},
{q:"Which example reflects an availability requirement within a policy?",options:["Hiding salaries from staff","Ensuring the payroll system is reachable on payday","Preventing edits to records","Signing each transaction"],answer:1,explanation:"Guaranteeing that an authorized system is reachable when needed is an availability requirement."},
{q:"A security model that deliberately limits expressiveness does so to achieve what?",options:["Faster networking","Analyzable safety properties","Larger storage","More ambiguity"],answer:1,explanation:"Because general safety is undecidable, restricted models trade expressiveness for the ability to analyze safety."},
{q:"Which pairing of access-control type and decision-maker is correct?",options:["MAC \u2192 resource owner","DAC \u2192 resource owner","ORCON \u2192 system only","DAC \u2192 originator only"],answer:1,explanation:"DAC places the access decision with the resource owner, which is the defining feature of discretionary control."},
{q:"Which statement about confidentiality and integrity trade-offs in policy is most accurate?",options:["They are always identical goals","A policy may emphasize one over the other depending on context","Integrity always overrides confidentiality","Neither can appear in one policy"],answer:1,explanation:"Different contexts (military vs commercial) emphasize confidentiality or integrity differently; policy reflects priorities."},
{q:"The overall purpose of a security policy can best be summarized as what?",options:["To list all system bugs","To define what secure means and separate allowed from forbidden states","To replace all mechanisms","To encrypt every file"],answer:1,explanation:"A security policy defines what 'secure' means for a system by partitioning states into authorized and unauthorized."}
];

window.QUESTIONS.ch4 = [
{q:"A cryptosystem is formally defined as a tuple containing which components?",options:["Users, roles, files, and keys","Encryption, decryption, plaintexts, keys, and ciphertexts","Threats, assets, risks, and controls","Subjects, objects, rights, and states"],answer:1,explanation:"A cryptosystem is the 5-tuple (E, D, M, K, C): encryption and decryption functions, messages, keys, and ciphertexts."},
{q:"What does Kerckhoffs's principle state about a cryptosystem's security?",options:["The algorithm must always be secret","Security should rest only on the secrecy of the key","Keys should be shared publicly","Encryption is unnecessary if hidden"],answer:1,explanation:"Kerckhoffs's principle says a system should stay secure even if everything but the key is public; security rests on the key."},
{q:"Why is 'security through obscurity' considered unreliable?",options:["Algorithms can leak or be reverse-engineered","Keys are impossible to generate","Obscurity makes keys longer","It always uses the one-time pad"],answer:0,explanation:"Hidden algorithms eventually leak or are reverse-engineered, so relying on their secrecy is unreliable."},
{q:"The Caesar cipher encrypts a letter using which operation?",options:["E_k(m) = (m \u00D7 k) mod 26","E_k(m) = (m + k) mod 26","E_k(m) = (m \u2212 26) mod k","E_k(m) = (k \u2212 m) mod 2"],answer:1,explanation:"The Caesar cipher shifts each letter by a fixed k: E_k(m) = (m + k) mod 26."},
{q:"Encrypting the letter 'A' (value 0) with a Caesar shift of 3 yields which letter?",options:["Letter X","Letter D","Letter C","Letter Z"],answer:1,explanation:"(0 + 3) mod 26 = 3, which corresponds to 'D'."},
{q:"Why is the Caesar cipher easily broken by brute force?",options:["It uses a very long random key","There are only 25 possible non-zero shifts","It uses public-key mathematics","It changes the key each letter"],answer:1,explanation:"With only 25 possible shifts, an attacker can simply try them all in seconds."},
{q:"In a ciphertext-only attack, what does the attacker have access to?",options:["Chosen plaintext-ciphertext pairs","Only ciphertext","The secret key directly","The full algorithm source code only"],answer:1,explanation:"In a ciphertext-only attack, the adversary sees only ciphertext and must deduce everything else."},
{q:"Which attack model is the most powerful for the attacker?",options:["Ciphertext-only","Chosen-plaintext","Brute-force only","No-knowledge"],answer:1,explanation:"In a chosen-plaintext attack the adversary can pick plaintexts and see their ciphertexts, the strongest of the listed models."},
{q:"A frequency analysis attack exploits which fact about a language?",options:["All letters appear equally often","Some letters appear far more often than others","Letters never repeat","Letters have no statistical pattern"],answer:1,explanation:"Languages have characteristic letter frequencies (e.g., 'e' is common in English), which break simple substitution ciphers."},
{q:"What distinguishes a transposition cipher from a substitution cipher?",options:["It replaces each symbol with another","It rearranges symbol positions without changing them","It uses public and private keys","It always uses a 56-bit key"],answer:1,explanation:"A transposition cipher reorders the symbols; the symbols themselves are unchanged, unlike substitution."},
{q:"The rail-fence cipher is an example of which cipher family?",options:["Substitution","Transposition","Public-key","Hashing"],answer:1,explanation:"The rail-fence rearranges letter positions in a zig-zag, making it a transposition cipher."},
{q:"The Vigen\u00E8re cipher is classified as which type of cipher?",options:["Monoalphabetic substitution","Polyalphabetic substitution","Pure transposition","Asymmetric cipher"],answer:1,explanation:"Vigen\u00E8re uses a repeating keyword to apply multiple Caesar shifts, making it polyalphabetic."},
{q:"In the Vigen\u00E8re cipher, what is the 'period'?",options:["The length of the repeating keyword","The number of ciphertext blocks","The size of the alphabet","The time to encrypt one letter"],answer:0,explanation:"The period is the length of the repeating keyword, which determines how the cipher cycles through shifts."},
{q:"Why does the Vigen\u00E8re cipher resist simple frequency analysis?",options:["It deletes common letters","It flattens letter frequencies across positions","It uses only one shift","It encrypts numbers, not letters"],answer:1,explanation:"Because different positions use different shifts, the cipher flattens frequencies, defeating naive frequency analysis."},
{q:"The Kasiski method helps an attacker determine what about a Vigen\u00E8re cipher?",options:["The plaintext language","The period (keyword length)","The encryption speed","The number of users"],answer:1,explanation:"Kasiski examines distances between repeated ciphertext sequences to deduce the period (keyword length)."},
{q:"The Index of Coincidence is used to estimate what?",options:["The keyword's exact letters","The period of a polyalphabetic cipher","The encryption key size in bits","The number of rounds in DES"],answer:1,explanation:"The Index of Coincidence statistically estimates the period of a polyalphabetic cipher like Vigen\u00E8re."},
{q:"Approximately what Index of Coincidence value is expected for random text?",options:["About 0.066","About 0.038","About 0.500","About 1.000"],answer:1,explanation:"Random text has an Index of Coincidence near 0.038, lower than the ~0.066 of monoalphabetic English."},
{q:"What three conditions make a one-time pad achieve perfect secrecy?",options:["Short key, reused often, predictable","Truly random key, as long as the message, used once","Public key, fixed length, shared widely","56-bit key, 16 rounds, S-boxes"],answer:1,explanation:"A one-time pad is perfectly secret only if the key is truly random, at least as long as the message, and never reused."},
{q:"Who proved that the one-time pad provides perfect secrecy?",options:["Rivest","Shannon","Kerckhoffs","Diffie"],answer:1,explanation:"Claude Shannon proved the one-time pad offers perfect (information-theoretic) secrecy."},
{q:"Why is the one-time pad impractical for most real uses?",options:["It is mathematically breakable","The key must be as long as the message and never reused","It only works on numbers","It requires public keys"],answer:1,explanation:"The key-management burden \u2014 a truly random key as long as the message, used once, securely distributed \u2014 makes it impractical."},
{q:"DES operates on plaintext blocks of what size?",options:["32 bits","64 bits","128 bits","256 bits"],answer:1,explanation:"DES is a block cipher that processes 64-bit blocks of data."},
{q:"What is the effective key length of DES?",options:["40 bits","56 bits","112 bits","128 bits"],answer:1,explanation:"DES uses a 56-bit effective key (8 of the 64 key bits are parity)."},
{q:"How many rounds does the DES algorithm use?",options:["8 rounds","16 rounds","24 rounds","32 rounds"],answer:1,explanation:"DES applies 16 rounds of its Feistel structure."},
{q:"What is the main security weakness of DES today?",options:["Its block size is too large","Its 56-bit key is vulnerable to brute force","It has no S-boxes","It cannot be implemented in hardware"],answer:1,explanation:"The 56-bit key space is small enough that modern hardware can exhaustively search it."},
{q:"What provides the non-linearity in each DES round?",options:["The parity bits","The substitution boxes (S-boxes)","The block size","The key length"],answer:1,explanation:"DES's S-boxes provide the non-linear substitution that gives the cipher its strength against linear analysis."},
{q:"Why is ECB mode considered insecure for many messages?",options:["It chains every block together","Identical plaintext blocks produce identical ciphertext blocks","It uses a different key each block","It requires public keys"],answer:1,explanation:"In ECB, equal plaintext blocks map to equal ciphertext blocks, leaking structural patterns in the data."},
{q:"Which mode chains blocks together using XOR to add diffusion?",options:["ECB mode","CBC mode","Raw mode","Identity mode"],answer:1,explanation:"CBC (Cipher Block Chaining) XORs each plaintext block with the previous ciphertext block, adding diffusion."},
{q:"CBC mode is described as 'self-healing' because what happens after a transmission error?",options:["All later blocks stay corrupted","Decryption recovers after the affected blocks","The key changes automatically","The whole message is lost"],answer:1,explanation:"In CBC, an error affects only the corrupted block and the next, after which decryption recovers correctly."},
{q:"What does 3DES (EDE) do to strengthen DES?",options:["Applies DES three times for a larger effective key","Removes the S-boxes","Shortens the key to 40 bits","Converts it to a hash function"],answer:0,explanation:"3DES applies the DES operation three times (encrypt-decrypt-encrypt), enlarging the effective key strength."},
{q:"AES (Rijndael) uses a block size of what?",options:["64 bits","128 bits","56 bits","256 bits"],answer:1,explanation:"AES uses a fixed 128-bit block size."},
{q:"Which key sizes does AES support?",options:["40, 56, or 64 bits","128, 192, or 256 bits","Only 56 bits","512 or 1024 bits"],answer:1,explanation:"AES supports key sizes of 128, 192, or 256 bits."},
{q:"Structurally, how does AES differ from DES?",options:["AES is a Feistel network like DES","AES is a substitution-permutation network, not Feistel","AES uses no substitution at all","AES has only one round"],answer:1,explanation:"AES is a substitution-permutation network, whereas DES uses a Feistel structure."},
{q:"In which year was public-key cryptography introduced by Diffie and Hellman?",options:["1956","1976","1990","2001"],answer:1,explanation:"Diffie and Hellman introduced public-key cryptography in 1976."},
{q:"In public-key cryptography, what is true about the key pair?",options:["Both keys are kept secret","One key is public and the other private","Both keys are published","Only one shared key exists"],answer:1,explanation:"Each user has a public key (shared openly) and a private key (kept secret); they work as a matched pair."},
{q:"To send a confidential message, you encrypt it with which key?",options:["Your own private key","The recipient's public key","A shared symmetric key only","The recipient's private key"],answer:1,explanation:"Encrypting with the recipient's public key means only their private key can decrypt it, ensuring confidentiality."},
{q:"To prove a message came from you (authentication), you encrypt/sign with which key?",options:["The recipient's public key","Your own private key","A random session key","The recipient's private key"],answer:1,explanation:"Signing with your private key lets anyone verify the message with your public key, proving its origin."},
{q:"On what mathematical problem does RSA's security rest?",options:["Sorting large lists","Factoring large numbers","Computing letter frequencies","Reversing a hash"],answer:1,explanation:"RSA's security depends on the difficulty of factoring the large modulus n into its prime factors."},
{q:"In RSA, given primes p and q, how is the modulus n computed?",options:["n = p + q","n = p \u00D7 q","n = p \u2212 q","n = p / q"],answer:1,explanation:"In RSA, the modulus n is the product of the two primes: n = p \u00D7 q."},
{q:"For RSA with p = 7 and q = 11, what is \u03C6(n)?",options:["77","60","18","70"],answer:1,explanation:"\u03C6(n) = (p\u22121)(q\u22121) = 6 \u00D7 10 = 60."},
{q:"In RSA, the encryption of message m is computed how?",options:["c = m \u00D7 e mod n","c = m^e mod n","c = e^m mod n","c = m + e mod n"],answer:1,explanation:"RSA encryption raises the message to the public exponent: c = m^e mod n."},
{q:"In RSA, decryption recovers the message using which formula?",options:["m = c \u00D7 d mod n","m = c^d mod n","m = d^c mod n","m = c + d mod n"],answer:1,explanation:"RSA decryption raises the ciphertext to the private exponent: m = c^d mod n."},
{q:"For RSA with \u03C6(n) = 60 and public exponent e = 17, the private exponent d satisfies which relation?",options:["e + d = 60","e \u00D7 d \u2261 1 (mod 60)","d = 60 \u2212 e","d = e^2 mod 60"],answer:1,explanation:"The private exponent d is the modular inverse of e: e \u00D7 d \u2261 1 (mod \u03C6(n)); here d = 53 since 17\u00D753 \u2261 1 (mod 60)."},
{q:"Why can the RSA public key (n, e) be shared openly without compromising security?",options:["Because n is never used","Because deriving d requires factoring n, which is infeasible","Because e is always secret","Because the message is never encrypted"],answer:1,explanation:"Recovering the private key requires \u03C6(n), which requires factoring n; for large n this is computationally infeasible."},
{q:"What is the primary purpose of a cryptographic checksum (hash)?",options:["To hide a message's content","To protect and verify data integrity","To distribute secret keys","To compress files for storage"],answer:1,explanation:"A cryptographic hash produces a fixed-size digest used to detect changes, protecting integrity."},
{q:"A defining property of a cryptographic hash function is that it is what?",options:["Easily reversible","One-way and collision-resistant","Dependent on a public key","Always 56 bits long"],answer:1,explanation:"Cryptographic hashes are one-way (hard to invert) and collision-resistant (hard to find two inputs with the same hash)."},
{q:"What does an HMAC add compared to a plain hash?",options:["It compresses the message","It uses a secret key to verify integrity and authenticity","It encrypts the message reversibly","It removes the need for hashing"],answer:1,explanation:"HMAC combines a secret key with a hash, verifying both that data is unaltered and that it came from a key holder."},
{q:"What is the key difference between hashing and encryption?",options:["Hashing is reversible; encryption is not","Encryption is reversible; hashing is one-way","Both are always reversible","Neither uses keys ever"],answer:1,explanation:"Encryption can be decrypted (reversible), while hashing is a one-way function that cannot be undone."},
{q:"Diffie-Hellman specifically enables two parties to do what?",options:["Factor large numbers quickly","Agree on a shared secret over an insecure channel","Hash messages without a key","Break the one-time pad"],answer:1,explanation:"Diffie-Hellman key exchange lets two parties establish a shared secret even over an insecure channel."},
{q:"Which statement best contrasts symmetric and public-key cryptography?",options:["Symmetric uses one shared key; public-key uses a key pair","Symmetric uses a key pair; public-key uses one shared key","Both use only public keys","Neither uses any keys"],answer:0,explanation:"Symmetric crypto uses a single shared secret key, while public-key crypto uses a matched public/private key pair."}
];

window.QUESTIONS.final = [
{q:"Which trio of properties is the foundation of information security?",options:["Confidentiality, Integrity, Availability","Authentication, Authorization, Auditing","People, Process, Technology","Detection, Response, Recovery"],answer:0,explanation:"The CIA triad \u2014 Confidentiality, Integrity, Availability \u2014 underlies all security goals."},
{q:"A flood of traffic that prevents legitimate users from reaching a service attacks which property?",options:["Confidentiality","Availability","Integrity","Authenticity"],answer:1,explanation:"Denial-of-service attacks target availability by blocking legitimate access."},
{q:"Which definition matches a vulnerability?",options:["A potential cause of harm","A weakness that can be exploited","The product of likelihood and impact","An asset of high value"],answer:1,explanation:"A vulnerability is a weakness that a threat can exploit, distinct from the threat itself."},
{q:"Risk is best expressed as the combination of which two factors?",options:["Asset value and key length","Likelihood and impact","Threat and availability","Policy and mechanism"],answer:1,explanation:"Risk reflects how likely a harmful event is and how damaging it would be."},
{q:"A firewall that blocks malicious packets before entry is which type of control?",options:["Preventive","Detective","Corrective","Administrative"],answer:0,explanation:"Preventive controls stop incidents before they occur, as a blocking firewall does."},
{q:"Restoring data from backups after an attack exemplifies which control?",options:["Preventive","Detective","Corrective","Deterrent"],answer:2,explanation:"Corrective controls restore normal operation after an incident."},
{q:"Security awareness training is best categorized as which kind of control?",options:["Physical","Administrative","Technical","Cryptographic"],answer:1,explanation:"Training is an administrative control \u2014 a policy/procedure guiding human behavior."},
{q:"What does authentication establish, in contrast to authorization?",options:["What a user may do","Who a user is","When a session ends","Where data is stored"],answer:1,explanation:"Authentication verifies identity; authorization then decides what that identity may do."},
{q:"The principle of least privilege recommends granting users what?",options:["Maximum possible access","Only the access they need","The same access as admins","Temporary full access"],answer:1,explanation:"Least privilege limits permissions to the minimum required, reducing potential damage."},
{q:"Phishing primarily exploits which weakness?",options:["Weak encryption keys","Human trust and behavior","Slow network links","Database indexing flaws"],answer:1,explanation:"Phishing is social engineering that manipulates people rather than breaking technology."},
{q:"Defense in depth is best described as which approach?",options:["A single strong barrier","Multiple layered, overlapping controls","Encrypting only key files","Trusting internal users fully"],answer:1,explanation:"Defense in depth layers controls so that one failure does not compromise the whole system."},
{q:"A zero-trust model is built on which assumption?",options:["Internal users are always safe","No user or device is trusted by default","Firewalls are enough alone","Encryption replaces access checks"],answer:1,explanation:"Zero trust verifies every request regardless of origin, trusting nothing by default."},
{q:"In the access-control model, a subject is best defined as what?",options:["A passive protected resource","An active entity performing operations","A permission in a cell","A rule limiting transitions"],answer:1,explanation:"A subject is an active entity (user, process, service) that initiates operations."},
{q:"Which is an example of an object in access control?",options:["A process requesting access","A stored file being read","A user issuing a command","A service starting a transfer"],answer:1,explanation:"Objects are passive resources acted upon, such as a file being read."},
{q:"Which classic right enables modification and thus threatens integrity if misused?",options:["Read","Write","Execute","Browse"],answer:1,explanation:"Write permits modification, so improper write access endangers integrity."},
{q:"In the access-control matrix, rows and columns represent what, respectively?",options:["Objects and subjects","Subjects and objects","Rights and states","Keys and files"],answer:1,explanation:"Rows are subjects and columns are objects in the access-control matrix."},
{q:"An access control list (ACL) corresponds to which part of the matrix?",options:["A row","A column","A diagonal","A single cell"],answer:1,explanation:"An ACL is organized per object, representing one column of the matrix."},
{q:"A capability list corresponds to which part of the matrix?",options:["A column","A row","A header","A merged cell"],answer:1,explanation:"A capability list is organized per subject, representing one row of the matrix."},
{q:"Which question is most directly answered by an ACL?",options:["What can this user access?","Who can access this object?","How many rights total exist?","When was a right revoked?"],answer:1,explanation:"Because ACLs list subjects per object, they answer 'who can access this object?'"},
{q:"Why is the access-control matrix usually stored as ACLs or capability lists?",options:["The matrix is mostly empty (sparse)","The matrix cannot hold rights","Lists encrypt the data","Lists remove all subjects"],answer:0,explanation:"The matrix is sparse, so storing it directly wastes space; ACLs and capability lists are compact slices."},
{q:"The safety problem asks whether a system can ever do what?",options:["Run out of storage","Leak a right to a subject that should not have it","Lose network connectivity","Expire a password"],answer:1,explanation:"The safety problem asks whether a particular right can ever leak to an unauthorized subject."},
{q:"The HRU result showed that the general safety problem is what?",options:["Always solvable quickly","Undecidable","Independent of commands","Only about encryption"],answer:1,explanation:"Harrison-Ruzzo-Ullman proved that, in general, safety is undecidable."},
{q:"Delegation in access control means a subject does what?",options:["Deletes another user","Grants a right it holds to another subject","Encrypts a file","Audits the logs"],answer:1,explanation:"Delegation passes a held permission to another subject, adding a matrix entry."},
{q:"A subject can only delegate a right that it does what?",options:["Invents on the spot","Actually possesses","Borrows from the system","Has never held"],answer:1,explanation:"You cannot give away a permission you do not have; delegation is limited to held rights."},
{q:"A security policy partitions system states into which two sets?",options:["Fast and slow","Authorized and unauthorized","Encrypted and plaintext","Public and private"],answer:1,explanation:"A policy separates states into authorized (secure) and unauthorized (non-secure)."},
{q:"Which statement correctly separates policy from mechanism?",options:["Policy is the tool; mechanism is the goal","Policy is what is allowed; mechanism is how it is enforced","They are the same thing","Mechanism defines the goal"],answer:1,explanation:"Policy describes what is allowed; mechanism is the technique enforcing it."},
{q:"A military (governmental) policy primarily aims to provide which property?",options:["Integrity","Confidentiality","Availability","Redundancy"],answer:1,explanation:"Military policies focus on confidentiality \u2014 preventing unauthorized disclosure."},
{q:"A commercial policy primarily aims to provide which property?",options:["Confidentiality","Integrity","Anonymity","Availability"],answer:1,explanation:"Commercial policies focus on integrity \u2014 preventing unauthorized modification."},
{q:"Under discretionary access control (DAC), who decides access?",options:["The system rules","The resource owner","The data's originator","A labeling authority"],answer:1,explanation:"DAC lets the resource owner decide access at their discretion."},
{q:"Under mandatory access control (MAC), who enforces access?",options:["The resource owner","The system or organization","The originator","Each end user"],answer:1,explanation:"MAC enforces access through system/organization rules that users cannot override."},
{q:"Under ORCON, who controls redistribution of information?",options:["The current holder","The originator who created it","The administrator","Any reader"],answer:1,explanation:"ORCON keeps redistribution control with the originator, even after sharing."},
{q:"Why is policy ambiguity dangerous?",options:["It speeds enforcement","It lets rules be interpreted differently, creating gaps","It removes mechanisms","It guarantees security"],answer:1,explanation:"Ambiguous policies invite inconsistent interpretation, leaving exploitable gaps."},
{q:"Why is trust an unavoidable part of security?",options:["Everything can be fully verified","At some point we rely on unverified assumptions","Trust removes vulnerabilities","Trust replaces policy"],answer:1,explanation:"Since not everything can be verified independently, security rests on some trusted assumptions."},
{q:"A cryptosystem is formally a 5-tuple consisting of which elements?",options:["E, D, M, K, C","S, O, R, P, Q","C, I, A, P, M","P, Q, N, E, D"],answer:0,explanation:"A cryptosystem is (E, D, M, K, C): encryption, decryption, messages, keys, ciphertexts."},
{q:"Kerckhoffs's principle says security should depend on what?",options:["The secrecy of the algorithm","The secrecy of the key","Hiding the ciphertext","Using short keys"],answer:1,explanation:"Security should rest only on the key, even if the algorithm is public."},
{q:"The Caesar cipher encrypts using which formula?",options:["E_k(m) = (m + k) mod 26","E_k(m) = (m \u00D7 k) mod 26","E_k(m) = m^k mod 26","E_k(m) = (k \u2212 m) mod 26"],answer:0,explanation:"The Caesar cipher shifts each letter: E_k(m) = (m + k) mod 26."},
{q:"Why is the Caesar cipher trivially broken?",options:["It uses a long random key","Only 25 non-zero shifts exist to try","It uses public keys","It changes keys each letter"],answer:1,explanation:"With only 25 possible shifts, brute force breaks it instantly."},
{q:"The Vigen\u00E8re cipher is which type of cipher?",options:["Monoalphabetic substitution","Polyalphabetic substitution","Transposition","Asymmetric"],answer:1,explanation:"Vigen\u00E8re uses a repeating keyword for multiple shifts, making it polyalphabetic."},
{q:"The Kasiski method and Index of Coincidence both help determine what?",options:["The plaintext meaning","The Vigen\u00E8re period (keyword length)","The DES key","The hash output"],answer:1,explanation:"Both techniques estimate the period of a polyalphabetic cipher like Vigen\u00E8re."},
{q:"Which conditions make a one-time pad perfectly secret?",options:["Short reused key","Truly random key, as long as the message, used once","Public key pair","56-bit key over 16 rounds"],answer:1,explanation:"Perfect secrecy requires a truly random key, at least as long as the message, used only once."},
{q:"What makes the one-time pad impractical despite being unbreakable?",options:["It is mathematically weak","Key length and distribution requirements","It only encrypts numbers","It needs a public key"],answer:1,explanation:"The key must be as long as the message, random, never reused, and securely shared \u2014 a heavy burden."},
{q:"DES uses which block size and effective key length?",options:["128-bit block, 56-bit key","64-bit block, 56-bit key","64-bit block, 128-bit key","128-bit block, 256-bit key"],answer:1,explanation:"DES uses a 64-bit block and a 56-bit effective key."},
{q:"What is DES's main weakness today?",options:["Its block is too large","Its 56-bit key is brute-forceable","It lacks any rounds","It cannot be implemented"],answer:1,explanation:"The 56-bit key space is small enough to brute force with modern hardware."},
{q:"Why is ECB mode insecure for structured data?",options:["It chains all blocks","Identical plaintext blocks yield identical ciphertext blocks","It uses a new key per block","It requires public keys"],answer:1,explanation:"ECB reveals patterns because equal plaintext blocks produce equal ciphertext blocks."},
{q:"AES (Rijndael) uses which block size?",options:["64 bits","128 bits","56 bits","512 bits"],answer:1,explanation:"AES uses a 128-bit block size."},
{q:"Which key sizes are supported by AES?",options:["40, 56, 64","128, 192, 256","56 only","512, 1024"],answer:1,explanation:"AES supports 128-, 192-, and 256-bit keys."},
{q:"Public-key cryptography was introduced by whom and when?",options:["Shannon, 1949","Diffie and Hellman, 1976","Rivest, 2001","Kerckhoffs, 1883"],answer:1,explanation:"Diffie and Hellman introduced public-key cryptography in 1976."},
{q:"To ensure confidentiality, a sender encrypts with which key?",options:["Their own private key","The recipient's public key","A shared symmetric key only","The recipient's private key"],answer:1,explanation:"Encrypting with the recipient's public key ensures only they can decrypt it."},
{q:"To authenticate the sender, a message is signed with which key?",options:["The recipient's public key","The sender's private key","A random session key","The recipient's private key"],answer:1,explanation:"Signing with the sender's private key lets anyone verify origin with the public key."},
{q:"RSA's security relies on the difficulty of which problem?",options:["Sorting numbers","Factoring large numbers","Computing frequencies","Reversing a transposition"],answer:1,explanation:"RSA depends on the hardness of factoring the modulus n into its primes."},
{q:"In RSA, the modulus n is computed as which of the following?",options:["n = p + q","n = p \u00D7 q","n = p \u2212 q","n = p^q"],answer:1,explanation:"RSA sets n = p \u00D7 q, the product of two primes."},
{q:"For RSA with p = 7 and q = 11, what is \u03C6(n)?",options:["77","60","70","18"],answer:1,explanation:"\u03C6(n) = (7\u22121)(11\u22121) = 6 \u00D7 10 = 60."},
{q:"In RSA, encryption is performed as which computation?",options:["c = m \u00D7 e mod n","c = m^e mod n","c = e^m mod n","c = m + e mod n"],answer:1,explanation:"RSA encryption computes c = m^e mod n."},
{q:"What is the primary purpose of a cryptographic hash?",options:["To hide message content","To verify data integrity","To exchange secret keys","To compress files"],answer:1,explanation:"A cryptographic hash protects integrity by detecting any change to the data."},
{q:"How does an HMAC differ from a plain hash?",options:["It compresses the message","It uses a secret key for integrity and authenticity","It encrypts reversibly","It removes hashing"],answer:1,explanation:"HMAC mixes a secret key with a hash, verifying both integrity and authenticity."},
{q:"What is the core difference between hashing and encryption?",options:["Hashing is reversible; encryption is not","Encryption is reversible; hashing is one-way","Both are reversible","Neither uses keys"],answer:1,explanation:"Encryption can be decrypted; hashing is a one-way function."},
{q:"Diffie-Hellman key exchange lets two parties do what?",options:["Factor numbers quickly","Agree on a shared secret over an insecure channel","Hash without a key","Break a one-time pad"],answer:1,explanation:"Diffie-Hellman establishes a shared secret over an insecure channel."},
{q:"Which statement correctly contrasts symmetric and asymmetric cryptography?",options:["Symmetric uses a key pair; asymmetric uses one key","Symmetric uses one shared key; asymmetric uses a key pair","Both use only public keys","Neither uses any key"],answer:1,explanation:"Symmetric crypto uses one shared key; asymmetric (public-key) uses a public/private pair."},
{q:"A process that initiates an operation and is also acted upon can be classified as what?",options:["Only an object","Both a subject and an object","Neither subject nor object","Only a right"],answer:1,explanation:"A process is a subject when it initiates and an object when acted upon, so it can be both."},
{q:"Which overall idea best captures the relationship between policy and CIA?",options:["Policy ignores CIA entirely","A policy decides which CIA properties matter and defines secure states","CIA replaces the need for policy","Policy is only about availability"],answer:1,explanation:"A security policy chooses which of confidentiality, integrity, and availability matter and partitions states accordingly."}
];
